const row = $input.first().json;

// Parse full variables JSON stored in tracker
let fullVars = {};
try {
  fullVars = JSON.parse(row.full_variables_json || '{}');
} catch(e) {
  fullVars = {};
}

// Re-read calculated price from Sheets (use stored value)
// Merge tracker row with full variables
const merged = {
  ...fullVars,
  ...row,
  // Ensure key fields come from tracker (may be manually edited)
  engagement_id: row.engagement_id,
  client_company: row.client_company || fullVars.client_company,
  coachee_name: row.coachee_name || fullVars.coachee_name,
  hubspot_deal_id: row.hubspot_deal_id || fullVars.hubspot_deal_id,
  coachName: row.coach_name || fullVars.coachName,
  tier: row.tier || fullVars.tier,
  billRate: parseFloat(row.bill_rate) || fullVars.billRate,
  num_participants: parseInt(row.num_participants) || fullVars.num_participants || 1,
  paymentStructure: row.payment_structure || fullVars.paymentStructure,
  netDays: parseInt(row.net_days) || fullVars.netDays || 30,
  totalEngagementPrice: parseFloat((row.total_engagement_price || '0').toString().replace(/[,$]/g, '')) || fullVars.totalEngagementPrice || 0,
  pricePerParticipant: parseFloat((row.price_per_participant || '0').toString().replace(/[,$]/g, '')) || fullVars.pricePerParticipant || 0,
  client_email: row.client_email || fullVars.client_email,
  rationaleDocUrl: row.rationale_doc_url || fullVars.rationaleDocUrl || '',
  // Restore nested objects from fullVars
  hours: fullVars.hours || {},
  reductions: fullVars.reductions || [],
  interview360Action: fullVars.interview360Action || 'KEEP',
  interviewCount: fullVars.interviewCount || 8,
  coachee_terminology: fullVars.coachee_terminology || 'client',
  flags: fullVars.flags || []
};

return [{ json: merged }];

const sheetsResponse = $input.first().json;
const prevData = $('Parse Tracker + Full Variables').first().json;

// Use latest price from sheet (reviewer may have adjusted)
const values = sheetsResponse.values || [];
const freshTotalPrice = parseFloat((values[2]?.[0] || values[0]?.[0] || '0').toString().replace(/[,$]/g, '')) || prevData.totalEngagementPrice;
const freshPerParticipant = parseFloat((values[0]?.[0] || '0').toString().replace(/[,$]/g, '')) || prevData.pricePerParticipant;

return [{ json: { ...prevData, totalEngagementPrice: freshTotalPrice, pricePerParticipant: freshPerParticipant } }];

const v = $input.first().json;

// Count stakeholder sessions to determine 'three' or 'four'
const stakeholderReduced = v.reductions?.some(r =>
  ['B38','B43','B45','B46'].includes(r.cell) && r.to <= 0.5
);
// If any stakeholder session eliminated → three; else four
const elimCount = ['B38','B43','B45','B46'].filter(c => (v.hours?.[c] || 0) === 0).length;
const stakeholderCountText = elimCount >= 1 ? 'three' : 'four';

// Dev History duration text
const devHistoryHours = v.hours?.B39 || 2.0;
let devHistoryText;
if (devHistoryHours === 0) {
  devHistoryText = ''; // SPARK_I: no dev history
} else if (devHistoryHours <= 1.5) {
  devHistoryText = '90-minute';
} else {
  devHistoryText = '2-hour';
}

// Assessment Feedback text (counterintuitive rule)
// 2hrs (default) → DELETE sentence (empty string)
// 1.5hrs → ADD sentence
const assessHours = v.hours?.B41 || 2.0;
const assessmentFeedbackText = assessHours <= 1.5
  ? 'This meeting is 90 minutes in duration.'
  : ''; // If 2hr, delete the duration sentence

// 360° interview count text
let interviewCountText = '';
if (v.interview360Action === 'ELIMINATE' || v.interviewCount === 0) {
  interviewCountText = '';
} else {
  interviewCountText = `up to ${v.interviewCount} confidential interviews`;
}

// Streams count: 360° removed → 'two' streams, else 'three'
const streamsCount = (v.interview360Action === 'ELIMINATE') ? 'two' : 'three';

// Dev Planning text
const devPlanningHours = v.hours?.B42 || 1.0;
const devPlanningText = devPlanningHours === 0 ? '' : '1-hour Development Planning Session';

// Format total price
const totalPriceFormatted = '$' + Math.round(v.totalEngagementPrice).toLocaleString('en-US');

// Build replacements map
const replacements = [
  { find: '{{HUBSPOT_ID}}',              replace: v.hubspot_deal_id || '[DEAL ID NEEDED]' },
  { find: '{{STAKEHOLDER_COUNT}}',       replace: stakeholderCountText },
  { find: '{{COACH_NAME}}',              replace: v.coachName || 'a Senior Level AIIR Consultant' },
  { find: '{{CLIENT_TERM}}',             replace: v.coachee_terminology || 'client' },
  { find: '{{DEV_HISTORY_TEXT}}',        replace: devHistoryText },
  { find: '{{INTERVIEW_COUNT}}',         replace: interviewCountText },
  { find: '{{STREAMS_COUNT}}',           replace: streamsCount },
  { find: '{{ASSESSMENT_FEEDBACK_TEXT}}',replace: assessmentFeedbackText },
  { find: '{{DEV_PLANNING_TEXT}}',       replace: devPlanningText },
  { find: '{{TOTAL_PRICE}}',             replace: totalPriceFormatted },
  { find: '{{PAYMENT_STRUCTURE}}',       replace: v.paymentStructure || '100% invoiced upon program kickoff' },
  { find: '{{NET_DAYS}}',                replace: String(v.netDays || 30) },
  { find: '{{CLIENT_COMPANY}}',          replace: v.client_company || '[CLIENT COMPANY]' }
];

const today = new Date().toISOString().split('T')[0];
const sowDate = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
replacements.push({ find: '{{SOW_DATE}}', replace: sowDate });

const docName = `${v.client_company || 'Client'}_${v.coachee_name || 'Coachee'}_${v.tier || 'IGNITE'}_SOW_DRAFT_${today}`;

return [{ json: { ...v, replacements, docName, today } }];

const copyResult = $input.first().json;
const prevData = $('Build SOW Field Map').first().json;
const newDocId = copyResult.id;
const newDocUrl = `https://docs.google.com/document/d/${newDocId}/edit`;
return [{ json: { ...prevData, newDocId, newDocUrl } }];

